import { IMessageDataWrapper, IMessageParser } from '@nitrots/nitro-renderer';

export class OpenAvatarEditorParser implements IMessageParser {
    private _mode: number = 0;

    public flush(): boolean {
        this._mode = 0;
        return true;
    }

    public parse(wrapper: IMessageDataWrapper): boolean {
        if (!wrapper) return false;

        // MUST match OpenAvatarEditorComposer.java:
        // this.response.appendInt(this.mode);
        this._mode = wrapper.readInt();

        return true;
    }

    public get mode(): number {
        return this._mode;
    }
}
